        .dashboard-container {
          position: relative;
          min-height: 100vh;
          background: #f8fafc;
          font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
        }

        /* Chatbot Widget */
        .chatbot-widget {
          position: fixed;
          bottom: 24px;
          right: 24px;
          z-index: 1000;
        }

        .chatbot-toggle-btn {
          width: 60px;
          height: 60px;
          border-radius: 50%;
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          color: white;
          border: none;
          display: flex;
          align-items: center;
          justify-content: center;
          cursor: pointer;
          box-shadow: 0 8px 32px rgba(102, 126, 234, 0.3);
          transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
          position: relative;
        }

        .chatbot-toggle-btn:hover {
          transform: translateY(-2px) scale(1.05);
          box-shadow: 0 12px 48px rgba(102, 126, 234, 0.4);
        }

        .chat-notification {
          position: absolute;
          top: -5px;
          right: -5px;
          background: #ef4444;
          color: white;
          border-radius: 50%;
          width: 24px;
          height: 24px;
          font-size: 12px;
          display: flex;
          align-items: center;
          justify-content: center;
          font-weight: 600;
          border: 2px solid white;
        }

        .chatbot-interface {
          position: absolute;
          bottom: 80px;
          right: 0;
          width: 420px;
          height: 680px;
          background: white;
          border-radius: 20px;
          box-shadow: 0 20px 60px rgba(0, 0, 0, 0.15);
          display: flex;
          flex-direction: column;
          opacity: 0;
          transform: translateY(20px) scale(0.95);
          pointer-events: none;
          transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
          overflow: hidden;
        }

        .chatbot-widget.open .chatbot-interface {
          opacity: 1;
          transform: translateY(0) scale(1);
          pointer-events: all;
        }

        .chat-header {
          padding: 20px;
          border-bottom: 1px solid #f1f5f9;
          display: flex;
          justify-content: space-between;
          align-items: center;
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          color: white;
        }

        .chat-header-info {
          display: flex;
          align-items: center;
          gap: 12px;
        }

        .chat-header h3 {
          margin: 0;
          font-size: 18px;
          font-weight: 600;
        }

        .chat-subtitle {
          margin: 4px 0 0;
          font-size: 13px;
          opacity: 0.9;
        }

        .chat-action-btn {
          background: rgba(255, 255, 255, 0.2);
          border: none;
          color: white;
          width: 36px;
          height: 36px;
          border-radius: 8px;
          display: flex;
          align-items: center;
          justify-content: center;
          cursor: pointer;
          transition: all 0.2s;
        }

        .chat-action-btn:hover {
          background: rgba(255, 255, 255, 0.3);
        }

        .chat-messages-container {
          flex: 1;
          overflow-y: auto;
          padding: 20px;
          display: flex;
          flex-direction: column;
          gap: 16px;
          background: #f8fafc;
        }

        .chat-message {
          display: flex;
          gap: 12px;
          animation: messageAppear 0.3s cubic-bezier(0.4, 0, 0.2, 1);
        }

        @keyframes messageAppear {
          from {
            opacity: 0;
            transform: translateY(10px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }

        .chat-message.user {
          align-self: flex-end;
          flex-direction: row-reverse;
        }

        .message-avatar {
          width: 36px;
          height: 36px;
          border-radius: 50%;
          background: white;
          border: 2px solid #e2e8f0;
          display: flex;
          align-items: center;
          justify-content: center;
          flex-shrink: 0;
          margin-top: 4px;
        }

        .chat-message.ai .message-avatar {
          background: #667eea;
          border-color: #667eea;
          color: white;
        }

        .chat-message.user .message-avatar {
          background: #10b981;
          border-color: #10b981;
          color: white;
        }

        .message-content-wrapper {
          max-width: 280px;
        }

        .message-content {
          background: white;
          padding: 16px;
          border-radius: 18px;
          border-bottom-left-radius: 4px;
          box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
        }

        .chat-message.user .message-content {
          background: #10b981;
          color: white;
          border-bottom-left-radius: 18px;
          border-bottom-right-radius: 4px;
        }

        .message-text {
          font-size: 14px;
          line-height: 1.5;
          color: #374151;
        }

        .chat-message.user .message-text {
          color: white;
        }

        .message-line-emphasis {
          font-weight: 600;
          margin: 8px 0;
        }

        .message-line-indent {
          margin-left: 20px;
          margin: 4px 0 4px 20px;
        }

        .message-data {
          margin-top: 12px;
          border-top: 1px solid #e5e7eb;
          padding-top: 12px;
        }

        .message-data details {
          font-size: 12px;
        }

        .message-data summary {
          cursor: pointer;
          color: #667eea;
          font-weight: 500;
        }

        .message-data pre {
          margin-top: 8px;
          padding: 12px;
          background: #f9fafb;
          border-radius: 8px;
          font-size: 11px;
          overflow: auto;
          max-height: 200px;
        }

        .message-meta {
          display: flex;
          gap: 8px;
          align-items: center;
          margin-top: 6px;
          font-size: 11px;
          color: #9ca3af;
          padding: 0 4px;
        }

        .chat-message.user .message-meta {
          justify-content: flex-end;
        }

        .message-processing {
          display: flex;
          align-items: center;
          gap: 4px;
        }

        .typing-indicator {
          display: flex;
          gap: 6px;
          padding: 16px 20px;
          background: white;
          border-radius: 18px;
          border-bottom-left-radius: 4px;
        }

        .typing-indicator span {
          width: 8px;
          height: 8px;
          background: #cbd5e1;
          border-radius: 50%;
          animation: typing 1.4s infinite ease-in-out;
        }

        .typing-indicator span:nth-child(2) {
          animation-delay: 0.2s;
        }

        .typing-indicator span:nth-child(3) {
          animation-delay: 0.4s;
        }

        @keyframes typing {
          0%, 60%, 100% { 
            transform: translateY(0); 
            opacity: 0.6;
          }
          30% { 
            transform: translateY(-8px); 
            opacity: 1;
          }
        }

        .quick-actions {
          display: flex;
          gap: 8px;
          padding: 0 20px 16px;
          border-bottom: 1px solid #f1f5f9;
        }

        .quick-action-btn {
          flex: 1;
          padding: 10px 12px;
          background: white;
          border: 1px solid #e5e7eb;
          border-radius: 12px;
          font-size: 13px;
          color: #4b5563;
          cursor: pointer;
          display: flex;
          align-items: center;
          justify-content: center;
          gap: 6px;
          transition: all 0.2s;
          font-weight: 500;
        }

        .quick-action-btn:hover {
          background: #f9fafb;
          border-color: #d1d5db;
          transform: translateY(-1px);
        }

        .suggestions-container {
          padding: 16px 20px;
          border-bottom: 1px solid #f1f5f9;
        }

        .suggestions-title {
          font-size: 13px;
          color: #6b7280;
          margin: 0 0 12px;
          font-weight: 500;
        }

        .suggestions-grid {
          display: flex;
          flex-direction: column;
          gap: 8px;
        }

        .suggestion-chip {
          background: #f9fafb;
          border: 1px solid #e5e7eb;
          border-radius: 12px;
          padding: 12px 16px;
          font-size: 14px;
          color: #374151;
          text-align: left;
          cursor: pointer;
          display: flex;
          justify-content: space-between;
          align-items: center;
          transition: all 0.2s;
        }

        .suggestion-chip:hover {
          background: white;
          border-color: #667eea;
          box-shadow: 0 4px 12px rgba(102, 126, 234, 0.1);
          transform: translateX(2px);
        }

        .chat-input-area {
          padding: 20px;
          display: flex;
          gap: 12px;
          background: white;
        }

        .chat-input-field {
          flex: 1;
          padding: 14px 20px;
          border: 2px solid #e5e7eb;
          border-radius: 14px;
          font-size: 14px;
          outline: none;
          transition: all 0.2s;
          background: #f9fafb;
        }

        .chat-input-field:focus {
          border-color: #667eea;
          background: white;
          box-shadow: 0 0 0 4px rgba(102, 126, 234, 0.1);
        }

        .send-message-btn {
          width: 52px;
          height: 52px;
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          color: white;
          border: none;
          border-radius: 14px;
          display: flex;
          align-items: center;
          justify-content: center;
          cursor: pointer;
          transition: all 0.2s;
          flex-shrink: 0;
        }

        .send-message-btn:hover:not(:disabled) {
          transform: scale(1.05);
          box-shadow: 0 8px 24px rgba(102, 126, 234, 0.3);
        }

        .send-message-btn:disabled {
          background: #d1d5db;
          cursor: not-allowed;
        }

        /* Dashboard Content */
        .dashboard-content {
          max-width: 1200px;
          margin: 0 auto;
          padding: 32px;
        }

        /* Insights Section */
        .insights-section {
          margin-bottom: 32px;
        }

        .insights-title {
          font-size: 18px;
          font-weight: 600;
          color: #111827;
          margin-bottom: 16px;
        }

        .insights-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
          gap: 16px;
        }

        .insight-card {
          background: white;
          padding: 20px;
          border-radius: 16px;
          border-left: 4px solid;
          display: flex;
          align-items: center;
          gap: 16px;
          cursor: pointer;
          transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
          box-shadow: 0 4px 20px rgba(0, 0, 0, 0.05);
        }

        .insight-card:hover {
          transform: translateY(-2px);
          box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1);
        }

        .insight-card.info {
          border-left-color: #3b82f6;
        }

        .insight-card.warning {
          border-left-color: #f59e0b;
        }

        .insight-card.success {
          border-left-color: #10b981;
        }

        .insight-icon-wrapper {
          width: 40px;
          height: 40px;
          border-radius: 12px;
          display: flex;
          align-items: center;
          justify-content: center;
          flex-shrink: 0;
        }

        .insight-card.info .insight-icon-wrapper {
          background: #dbeafe;
          color: #3b82f6;
        }

        .insight-card.warning .insight-icon-wrapper {
          background: #fef3c7;
          color: #f59e0b;
        }

        .insight-card.success .insight-icon-wrapper {
          background: #d1fae5;
          color: #10b981;
        }

        .insight-text-content {
          flex: 1;
          font-size: 14px;
          color: #4b5563;
          line-height: 1.5;
        }

        .insight-arrow {
          color: #9ca3af;
        }

        /* Dashboard Header */
        .dashboard-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 32px;
          padding: 32px;
          background: white;
          border-radius: 20px;
          box-shadow: 0 8px 32px rgba(0, 0, 0, 0.05);
        }

        .student-profile {
          display: flex;
          gap: 24px;
          align-items: center;
        }

        .student-avatar {
          width: 100px;
          height: 100px;
          border-radius: 20px;
          overflow: hidden;
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          display: flex;
          align-items: center;
          justify-content: center;
          box-shadow: 0 8px 32px rgba(102, 126, 234, 0.2);
        }

        .avatar-image {
          width: 100%;
          height: 100%;
          object-fit: cover;
        }

        .avatar-placeholder {
          font-size: 40px;
          font-weight: 700;
          color: white;
        }

        .student-info {
          flex: 1;
        }

        .student-name {
          margin: 0 0 8px;
          font-size: 28px;
          font-weight: 700;
          color: #111827;
        }

        .student-id {
          font-size: 14px;
          color: #6b7280;
          margin-bottom: 12px;
        }

        .student-details {
          display: flex;
          flex-wrap: wrap;
          gap: 16px;
          margin-bottom: 16px;
        }

        .detail-item {
          font-size: 14px;
          color: #4b5563;
          padding: 6px 12px;
          background: #f9fafb;
          border-radius: 8px;
        }

        .student-badges {
          display: flex;
          gap: 8px;
          flex-wrap: wrap;
        }

        .badge {
          padding: 8px 16px;
          background: #e0e7ff;
          color: #3730a3;
          border-radius: 12px;
          font-size: 13px;
          font-weight: 600;
        }

        .badge.scholarship {
          background: #d1fae5;
          color: #065f46;
        }

        .academic-stats {
          display: flex;
          gap: 24px;
        }

        .stat-card {
          padding: 24px;
          background: #f9fafb;
          border-radius: 16px;
          text-align: center;
          min-width: 140px;
        }

        .stat-label {
          font-size: 13px;
          color: #6b7280;
          margin-bottom: 8px;
        }

        .stat-value {
          font-size: 32px;
          font-weight: 700;
          color: #111827;
        }

        /* Summary Cards */
        .summary-cards {
          display: grid;
          grid-template-columns: repeat(3, 1fr);
          gap: 24px;
          margin-bottom: 32px;
        }

        .summary-card {
          background: white;
          padding: 24px;
          border-radius: 20px;
          box-shadow: 0 8px 32px rgba(0, 0, 0, 0.05);
        }

        .card-title {
          font-size: 18px;
          font-weight: 600;
          color: #111827;
          margin: 0 0 20px;
        }

        .progress-container {
          margin-bottom: 16px;
        }

        .progress-bar {
          height: 12px;
          background: #f3f4f6;
          border-radius: 6px;
          overflow: hidden;
          margin-bottom: 8px;
        }

        .progress-fill {
          height: 100%;
          background: linear-gradient(90deg, #667eea 0%, #764ba2 100%);
          border-radius: 6px;
          transition: width 1s ease-in-out;
        }

        .progress-text {
          display: flex;
          justify-content: space-between;
          font-size: 14px;
          color: #6b7280;
        }

        .metrics-grid {
          display: grid;
          grid-template-columns: repeat(2, 1fr);
          gap: 16px;
          margin-bottom: 16px;
        }

        .metric {
          text-align: center;
        }

        .metric-label {
          font-size: 12px;
          color: #6b7280;
          margin-bottom: 4px;
        }

        .metric-value {
          font-size: 24px;
          font-weight: 700;
          color: #111827;
        }

        .action-buttons {
          display: flex;
          flex-direction: column;
          gap: 12px;
        }

        .action-button {
          padding: 14px 20px;
          border-radius: 12px;
          font-size: 14px;
          font-weight: 500;
          display: flex;
          align-items: center;
          justify-content: center;
          gap: 8px;
          cursor: pointer;
          transition: all 0.2s;
          border: none;
        }

        .action-button.primary {
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          color: white;
        }

        .action-button.primary:hover {
          transform: translateY(-2px);
          box-shadow: 0 8px 24px rgba(102, 126, 234, 0.3);
        }

        .action-button.secondary {
          background: #f3f4f6;
          color: #374151;
        }

        .action-button.secondary:hover {
          background: #e5e7eb;
        }

        .action-button.ghost {
          background: transparent;
          color: #6b7280;
          border: 1px solid #e5e7eb;
        }

        .action-button.ghost:hover {
          background: #f9fafb;
        }

        .card-footer {
          margin-top: 20px;
          padding-top: 16px;
          border-top: 1px solid #f3f4f6;
        }

        .footer-text {
          font-size: 13px;
          color: #6b7280;
        }

        /* Courses Section */
        .courses-section {
          margin-bottom: 32px;
        }

        .section-title {
          font-size: 24px;
          font-weight: 700;
          color: #111827;
          margin: 0 0 24px;
        }

        .courses-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
          gap: 20px;
        }

        .empty-state {
          grid-column: 1 / -1;
          text-align: center;
          padding: 40px;
          background: white;
          border-radius: 16px;
          color: #6b7280;
          font-size: 16px;
        }

        .course-card {
          background: white;
          padding: 24px;
          border-radius: 16px;
          box-shadow: 0 4px 20px rgba(0, 0, 0, 0.05);
          transition: all 0.3s;
        }

        .course-card:hover {
          transform: translateY(-4px);
          box-shadow: 0 12px 32px rgba(0, 0, 0, 0.1);
        }

        .course-header {
          display: flex;
          justify-content: space-between;
          align-items: flex-start;
          margin-bottom: 16px;
        }

        .course-code {
          font-size: 16px;
          font-weight: 700;
          color: #111827;
        }

        .course-meta {
          display: flex;
          flex-direction: column;
          align-items: flex-end;
          gap: 8px;
        }

        .course-status {
          padding: 4px 12px;
          border-radius: 20px;
          font-size: 12px;
          font-weight: 600;
        }

        .course-status.completed {
          background: #d1fae5;
          color: #065f46;
        }

        .course-status.enrolled, .course-status.registered {
          background: #dbeafe;
          color: #1e40af;
        }

        .course-status.in-progress {
          background: #fef3c7;
          color: #92400e;
        }

        .course-grade {
          font-size: 20px;
          font-weight: 700;
          color: #111827;
        }

        .course-body h4 {
          margin: 0 0 12px;
          font-size: 18px;
          font-weight: 600;
          color: #111827;
        }

        .course-details {
          display: flex;
          gap: 16px;
          font-size: 14px;
          color: #6b7280;
        }

        /* Semesters Section */
        .semesters-table {
          background: white;
          border-radius: 16px;
          overflow: hidden;
          box-shadow: 0 4px 20px rgba(0, 0, 0, 0.05);
