        .table-header, .table-row {
          display: grid;
          grid-template-columns: 80px 100px 80px 100px 200px 1fr;
          gap: 20px;
          padding: 20px;
          align-items: center;
        }

        .table-header {
          background: #f9fafb;
          font-weight: 600;
          color: #374151;
          border-bottom: 2px solid #e5e7eb;
        }

        .table-row {
          border-bottom: 1px solid #f3f4f6;
          transition: background 0.2s;
