          padding: 4px 12px;
          border-radius: 12px;
          font-size: 12px;
          font-weight: 600;
        }

        .status-badge.completed {
          background: #d1fae5;
          color: #065f46;
        }

        .status-badge.in-progress {
          background: #fef3c7;
          color: #92400e;
        }

        .status-badge.upcoming {
          background: #e0e7ff;
          color: #3730a3;
        }

        .courses-cell {
          max-height: 120px;
          overflow-y: auto;
        }

        .course-item {
          font-size: 13px;
          margin-bottom: 8px;
          padding: 8px;
          background: #f9fafb;
          border-radius: 8px;
        }

        .more-courses {
          font-size: 12px;
          color: #6b7280;
          text-align: center;
          padding: 8px;
          background: #f3f4f6;
          border-radius: 8px;
        }

        /* Loader and Error States */
        .loader-container, .error-container {
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
